#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#define MAX 100005

struct Island {
    int x, y;
};

int compare(const void *a, const void *b) {
    struct Island *island1 = (struct Island *)a;
    struct Island *island2 = (struct Island *)b;
    return island1->x - island2->x;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        struct Island islands[N];
        for (int i = 0; i < N; i++) {
            scanf("%d %d", &islands[i].x, &islands[i].y);
        }
        qsort(islands, N, sizeof(struct Island), compare);
        int lighthouses = 0;
        int illuminated[N];
        memset(illuminated, 0, sizeof(illuminated));
        for (int i = 0; i < N; i++) {
            if (!illuminated[i]) {
                lighthouses++;
                illuminated[i] = 1;
                for (int j = i + 1; j < N; j++) {
                    if (islands[j].x >= islands[i].x && islands[j].y <= islands[i].y) {
                        illuminated[j] = 1;
                    }
                }
            }
        }
        printf("%d\n", lighthouses);
        for (int i = 0; i < N; i++) {
            if (illuminated[i]) {
                printf("%d NW\n", i + 1);
            }
        }
    }
    return 0;
}

