import java.util.Arrays;
import java.util.Scanner;

public class Main {
    static class Island implements Comparable<Island> {
        int x, y;
        Island(int x, int y) {
            this.x = x;
            this.y = y;
        }
        @Override
        public int compareTo(Island o) {
            return this.x - o.x;
        }
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            Island[] islands = new Island[N];
            for (int i = 0; i < N; i++) {
                islands[i] = new Island(scanner.nextInt(), scanner.nextInt());
            }
            Arrays.sort(islands);
            int lighthouses = 0;
            boolean[] illuminated = new boolean[N];
            for (int i = 0; i < N; i++) {
                if (!illuminated[i]) {
                    lighthouses++;
                    illuminated[i] = true;
                    for (int j = i + 1; j < N; j++) {
                        if (islands[j].x >= islands[i].x && islands[j].y <= islands[i].y) {
                            illuminated[j] = true;
                        }
                    }
                }
            }
            System.out.println(lighthouses);
            for (int i = 0; i < N; i++) {
                if (illuminated[i]) {
                    System.out.println((i + 1) + " NW");
                }
            }
        }
    }
}

